      "path": "scope-service.js",
      "content": "function validateScopes(requestedScopes, clientId, store) {
  const client = store.clients.get(clientId);
  if (!client) throw new Error("Unknown client");

  // Map old scopes to new equivalents and collect all requested new scopes
  const allRequestedNewScopes = new Set();
  const hasOldScopes = requestedScopes.some(scope => store.scopeMapping[scope]);

  for (const scope of requestedScopes) {
    if (store.scopeMapping[scope]) {
      // Old scope - map to new equivalents
      for (const newScope of store.scopeMapping[scope]) {
        allRequestedNewScopes.add(newScope);
      }
    } else if (store.validNewScopes.has(scope)) {
      // New scope - add directly
      allRequestedNewScopes.add(scope);
    } else {
      // Invalid scope
      throw new Error(`Invalid scope: ${scope}`);
    }
  }

  // Convert to array for easier handling
  const requestedNewScopesArray = Array.from(allRequestedNewScopes);

  // Get client's approved scopes in new format
  const approvedNewScopes = new Set(client.grantedNewScopes);

  // Find intersection of requested and approved scopes (scope downgrade)
  const grantedScopes = requestedNewScopesArray.filter(scope => approvedNewScopes.has(scope));

  // If no scopes granted, throw error
  if (grantedScopes.length === 0) {
    throw new Error(`No valid scopes granted for client ${clientId}`);
  }

  // Log deprecation if old scopes were used
  if (hasOldScopes) {
    store.deprecationLog.push({
      clientId,
      requestedScopes,
      mappedScopes: grantedScopes,
      timestamp: Date.now()
    });
  }

  return grantedScopes;
}

function issueToken(requestedScopes, clientId, store) {
  const validatedScopes = validateScopes(requestedScopes, clientId, store);
  return {
    access_token: `at_${Date.now()}`,
    token_type: "Bearer",
    scope: validatedScopes.join(" "),
    expires_in: 300,
  };
}

function refreshWithScopes(refreshToken, store) {
  const tokenData = store.refreshTokens.get(refreshToken);
  if (!tokenData) throw new Error("Invalid refresh token");

  // Issues new token with whatever scopes are on the refresh token
  return issueToken(tokenData.scopes, tokenData.clientId, store);
}

function getGrantedScopes(clientId, store) {
  const client = store.clients.get(clientId);
  if (!client) throw new Error("Unknown client");
  return client.grantedNewScopes;
}

module.exports = { validateScopes, issueToken, refreshWithScopes, getGrantedScopes };"
